compliant:
#include <fstream>
#include <iostream>
#include <stdexcept>

// Compliant: Specific exception handling
void readFile() {
    try {
        std::ifstream file("test.txt");
        if (!file.is_open()) {
            throw std::ios_base::failure("Failed to open file");
        }
        // File operations
    } catch (const std::ios_base::failure& e) {
        std::cerr << "File operation failed: " << e.what() << std::endl;
    } catch (const std::bad_alloc& e) {
        std::cerr << "Memory allocation failed: " << e.what() << std::endl;
    }
}

// Another compliant example with multiple specific catches
void processData() {
    try {
        performCalculation();
        writeToDatabase();
        sendNetworkRequest();
    } catch (const std::invalid_argument& e) {
        handleCalculationError(e);
    } catch (const DatabaseException& e) {
        handleDatabaseError(e);
    } catch (const NetworkException& e) {
        handleNetworkError(e);
    }
}

// Acceptable use of general catch as last resort
void safeOperation() {
    try {
        riskyOperation();
    } catch (const SpecificException1& e) {
        handleSpecific1(e);
    } catch (const SpecificException2& e) {
        handleSpecific2(e);
    } catch (...) {
        // Only as last resort after specific handlers
        logUnexpectedException();
        throw;  // Re-throw to maintain exception propagation
    }
}
